import React, { useState, useEffect } from "react";
import axios from "axios";
import { ESTADOS, fetchCidades, enderecoVazio, enderecoParaPayload, EnderecoForm } from "../utils/endereco";

function CadastrarIdosoComponent() {
    const [nome, setNome] = useState("");
    const [cpf, setCpf] = useState("");
    const [dataNascimento, setDataNascimento] = useState("");
    const [telefone, setTelefone] = useState("");
    const [email, setEmail] = useState("");
    const [ativo, setAtivo] = useState(true);
    const [contatoEmergencia, setContatoEmergencia] = useState("");
    const [origem, setOrigem] = useState<EnderecoForm>(enderecoVazio());
    const [destino, setDestino] = useState<EnderecoForm>(enderecoVazio());
    const [cidadesOrigem, setCidadesOrigem] = useState<{ id: number; nome: string }[]>([]);
    const [cidadesDestino, setCidadesDestino] = useState<{ id: number; nome: string }[]>([]);
    const [loading, setLoading] = useState(false);
    const [mensagem, setMensagem] = useState<string | null>(null);

    useEffect(() => {
        if (!origem.estado) {
            setCidadesOrigem([]);
            return;
        }
        fetchCidades(origem.estado).then(setCidadesOrigem).catch(() => setCidadesOrigem([]));
    }, [origem.estado]);

    useEffect(() => {
        if (!destino.estado) {
            setCidadesDestino([]);
            return;
        }
        fetchCidades(destino.estado).then(setCidadesDestino).catch(() => setCidadesDestino([]));
    }, [destino.estado]);

    const limparFormulario = () => {
        setNome("");
        setCpf("");
        setDataNascimento("");
        setTelefone("");
        setEmail("");
        setAtivo(true);
        setContatoEmergencia("");
        setOrigem(enderecoVazio());
        setDestino(enderecoVazio());
    };

    const handleSubmit = async (event: React.FormEvent) => {
        event.preventDefault();
        setMensagem(null);
        setLoading(true);

        try {
            await axios.post("http://localhost:8080/idosos", {
                nome,
                cpf,
                dataNascimento,
                telefone,
                email,
                ativo,
                contatoEmergencia
            });
            setMensagem("Idoso cadastrado com sucesso.");
            limparFormulario();
        } catch (error) {
            setMensagem("Erro ao cadastrar idoso.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="container">
            <h2 className="mb-4">Cadastrar Idoso</h2>
            {mensagem && (
                <div className="alert alert-info">{mensagem}</div>
            )}
            <form onSubmit={handleSubmit}>
                <div className="row">
                    <div className="col-md-6 mb-3">
                        <label className="form-label">Nome:</label>
                        <input
                            type="text"
                            className="form-control"
                            value={nome}
                            onChange={(e) => setNome(e.target.value)}
                            disabled={loading}
                            required
                        />
                    </div>
                    <div className="col-md-6 mb-3">
                        <label className="form-label">CPF:</label>
                        <input
                            type="text"
                            className="form-control"
                            value={cpf}
                            onChange={(e) => setCpf(e.target.value)}
                            disabled={loading}
                            required
                        />
                    </div>
                </div>

                <div className="row">
                    <div className="col-md-6 mb-3">
                        <label className="form-label">Data de Nascimento:</label>
                        <input
                            type="date"
                            className="form-control"
                            value={dataNascimento}
                            onChange={(e) => setDataNascimento(e.target.value)}
                            disabled={loading}
                            max={new Date().toISOString().split("T")[0]}
                            required
                        />
                    </div>
                    <div className="col-md-6 mb-3">
                        <label className="form-label">Telefone:</label>
                        <input
                            type="text"
                            className="form-control"
                            value={telefone}
                            onChange={(e) => setTelefone(e.target.value)}
                            disabled={loading}
                        />
                    </div>
                </div>

                <div className="row">
                    <div className="col-md-6 mb-3">
                        <label className="form-label">Email:</label>
                        <input
                            type="email"
                            className="form-control"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            disabled={loading}
                        />
                    </div>
                    <div className="col-md-6 mb-3">
                        <label className="form-label">Contato de Emergência:</label>
                        <input
                            type="text"
                            className="form-control"
                            value={contatoEmergencia}
                            onChange={(e) => setContatoEmergencia(e.target.value)}
                            disabled={loading}
                        />
                    </div>
                </div>

                <div className="mb-3">
                    <div className="form-check">
                        <input
                            className="form-check-input"
                            type="checkbox"
                            checked={ativo}
                            onChange={(e) => setAtivo(e.target.checked)}
                            disabled={loading}
                            id="idosoAtivo"
                        />
                        <label className="form-check-label" htmlFor="idosoAtivo">
                            Ativo
                        </label>
                    </div>
                </div>

                <button type="submit" className="btn btn-primary" disabled={loading}>
                    Cadastrar Idoso
                </button>
            </form>
            {loading && <div className="loading-footer">Carregando...</div>}
        </div>
    );
}

export default CadastrarIdosoComponent;
